const result = $input.item.json;
const data = result.data;

if (!data || result.status !== 'success') {
  return [{ json: { error: 'Prometheus query failed', raw: result } }];
}

const resultType = data.resultType;
const results = data.result || [];

if (results.length === 0) {
  return [{ json: { message: 'Query returned no data. The metric may not exist or the target is down.', promql: $('Workflow Input').item.json.promql } }];
}

// Format for the AI agent to read easily
let formatted;
if (resultType === 'vector') {
  formatted = results.map(r => {
    const labels = Object.entries(r.metric)
      .filter(([k]) => k !== '__name__')
      .map(([k,v]) => `${k}=${v}`).join(', ');
    const value = parseFloat(r.value[1]);
    return `  ${r.metric.__name__ || 'value'}{${labels}} = ${value.toFixed(4)}`;
  }).join('\n');
} else if (resultType === 'matrix') {
  formatted = results.map(r => {
    const labels = Object.entries(r.metric)
      .filter(([k]) => k !== '__name__')
      .map(([k,v]) => `${k}=${v}`).join(', ');
    const latest = r.values[r.values.length - 1];
    const latestVal = parseFloat(latest[1]).toFixed(4);
    return `  ${r.metric.__name__ || 'value'}{${labels}} latest=${latestVal} (${r.values.length} samples)`;
  }).join('\n');
} else {
  formatted = JSON.stringify(data.result, null, 2);
}

return [{
  json: {
    result_type: resultType,
    series_count: results.length,
    formatted_result: formatted,
    message: `Prometheus query successful (${results.length} series, type=${resultType}):\n${formatted}`
  }
}];
